// n8n compatible version - processes input items and returns properly formatted output
function processData(items) {
  // Create a new array to hold the processed items
  return items.map(item => {
    const htmlData = item.json.data || item.json.html || JSON.stringify(item.json);

    try {
      // Find the start of the JSON data
      const jsonStartIndex = htmlData.indexOf('"archiveTypes"');
      if (jsonStartIndex === -1) {
        // Return the original item with an error message
        return {
          json: {
            ...item.json,
            sdVideoUrl: null,
            error: "Could not find video data"
          }
        };
      }

      // Create a valid JSON string by adding braces around it
      const jsonString = '{' + htmlData.substring(jsonStartIndex);

      // Find the videos array
      const videosStartIndex = jsonString.indexOf('"videos":[');
      if (videosStartIndex === -1) {
        return {
          json: {
            ...item.json,
            sdVideoUrl: null,
            error: "No videos array found"
          }
        };
      }

      // Extract the SD video URL using regex
      const sdUrlRegex = /"video_sd_url":"([^"]+)"/;
      const match = jsonString.match(sdUrlRegex);

      if (match && match[1]) {
        // Unescape the URL
        const sdVideoUrl = match[1].replace(/\\\//g, '/');

        // Return the original item plus the extracted URL
        return {
          json: {
            ...item.json,
            sdVideoUrl: sdVideoUrl
          }
        };
      } else {
        return {
          json: {
            ...item.json,
            sdVideoUrl: null,
            error: "SD video URL not found"
          }
        };
      }
    } catch (error) {
      // Return the original item with the error
      return {
        json: {
          ...item.json,
          sdVideoUrl: null,
          error: error.message
        }
      };
    }
  });
}

// This is what n8n expects
return processData($input.all());

