// Enhanced code node for EGP AI transcript processing
// Get the extracted data from the Extract from File node
const items = $input.all();
const item = items[0];

// Extract the transcript data from the text extraction
const extractedData = item.json;
const transcriptText = extractedData.data || '';

// Get the filename from the Ads Training Data node
const fileName = $('Sales Call').first().json['Sales Call File'].filename;
const triggerData = $('On form submission').item.json;
const userTitle = triggerData["Title/Source Name"] || '';
const creationDate = new Date().toISOString();

// ... rest of the code stays the same

if (!transcriptText) {
  throw new Error('No text content extracted from file');
}

// Create source name - use user title if provided, otherwise filename
const sourceName = userTitle.trim() || fileName;

// Extract basic info about the transcript
function analyzeTranscriptType(text) {
  const content = text.toLowerCase();

  // Determine format type
  let format = 'Course transcript';
  if (content.includes('vsl') || content.includes('video sales letter')) format = 'VSL';
  if (content.includes('ad copy') || content.includes('facebook ad')) format = 'Static ad';
  if (content.includes('sales call') || content.includes('discovery call')) format = 'Sales call';

  // Determine industry
  let industry = 'General business';
  if (content.includes('agency') || content.includes('smma')) industry = 'Marketing agencies';
  if (content.includes('recruitment') || content.includes('hiring')) industry = 'Recruitment';
  if (content.includes('ecommerce') || content.includes('e-commerce')) industry = 'E-commerce';
  if (content.includes('saas') || content.includes('software')) industry = 'SaaS';
  if (content.includes('coaching') || content.includes('consultant')) industry = 'Coaches/consultants';

  return { format, industry };
}

const transcriptAnalysis = analyzeTranscriptType(transcriptText);

// CHUNKING FUNCTION - Split text into optimal chunks
function chunkText(text, maxChunkSize = 1500, overlap = 200) {
  const chunks = [];
  const sentences = text.split(/[.!?]+/).filter(s => s.trim().length > 0);

  let currentChunk = '';
  let currentSize = 0;

  for (const sentence of sentences) {
    const sentenceLength = sentence.trim().length;

    // If adding this sentence would exceed max size, save current chunk
    if (currentSize + sentenceLength > maxChunkSize && currentChunk.length > 0) {
      chunks.push(currentChunk.trim());

      // Start new chunk with overlap from end of previous chunk
      const words = currentChunk.split(' ');
      const overlapWords = words.slice(-Math.floor(overlap / 6)); // Rough word estimate
      currentChunk = overlapWords.join(' ') + ' ' + sentence.trim();
      currentSize = currentChunk.length;
    } else {
      currentChunk += (currentChunk ? '. ' : '') + sentence.trim();
      currentSize = currentChunk.length;
    }
  }

  // Add the final chunk
  if (currentChunk.trim().length > 0) {
    chunks.push(currentChunk.trim());
  }

  return chunks;
}

// Create the base content without source prefix (for chunking)
const baseContent = `Date: ${creationDate}
Type: ${transcriptAnalysis.format}
Industry: ${transcriptAnalysis.industry}
Title: ${userTitle}

TRANSCRIPT CONTENT:
${transcriptText}`.trim();

// Chunk the content
const chunks = chunkText(baseContent, 1500, 200);

// Create metadata template
const baseMetadata = {
  document_type: "ad_script_transcript",
  source_file: fileName,
  source_name: sourceName,
  user_title: userTitle,
  upload_date: new Date().toISOString(),
  creation_date: creationDate,
  transcript_type: transcriptAnalysis.format,
  industry: transcriptAnalysis.industry,
  data_version: "1.0",
  file_type: "text",
  text_length: transcriptText.length,
  chunk_count: chunks.length
};

// Create output array - one item per chunk, each with source prefix
const outputChunks = chunks.map((chunk, index) => {
  // Add source prefix to EVERY chunk (this is what makes it searchable)
  const sourcePrefix = `SOURCE: ${sourceName}\n\n`;
  const contentWithSource = sourcePrefix + chunk;

  // Add chunk-specific metadata
  const chunkMetadata = {
    ...baseMetadata,
    chunk_index: index + 1,
    total_chunks: chunks.length,
    chunk_summary: chunk.substring(0, 200) + '...' // First 200 chars as summary
  };

  return {
    content: contentWithSource,
    metadata: chunkMetadata
  };
});

// Return array of chunks - each will be processed separately in the loop
return outputChunks;

